This patch fixes the problem.

Index: e_jn.c
===================================================================
--- e_jn.c	(revision 204219)
+++ e_jn.c	(working copy)
@@ -200,7 +200,12 @@
 			}
 	     	    }
 		}
-	    	b = (t*__ieee754_j0(x)/b);
+		z = __ieee754_j0(x);
+		w = __ieee754_j1(x);
+		if (fabs(z) >= fabs(w))
+	    		b = (t*z/b);
+		else
+			b = (t*w/a);		
 	    }
 	}
 	if(sgn==1) return -b; else return b;

